lity = z.infer<typeof harnessAvailabilitySchema>;\n    97\texport type ProviderMatrix = z.infer<typeof providerMatrixSchema>;\n    98\texport type VerificationGates = z.infer<typeof verificationGatesSchema>;\n    99\texport type PreflightResult = z.infer<typeof preflightResultSchema>;\n   100\t\n   101\tfunction statusForOutcome(outcome: string): CliStatus {\n   102\t  switch (outcome) {\n   103\t    case \"ready\":\n   104\t      return \"ok\";\n   105\t    case \"needs-user-decision\":\n   106\t      return \"needs-user-decision\";\n   107\t    case \"blocked\":\n   108\t      return \"blocked\";\n   109\t    default:\n   110\t      return \"error\";\n   111\t  }\n   112\t}\n   113\t\n   114\texport function exitCodeForStatus(status: CliStatus): number {\n   115\t  switch (status) {\n   116\t    case \"ok\":\n   117\t      return 0;\n   118\t    case \"needs-user-decision\":\n   119\t      return 2;\n   120\t    case \"blocked\":\n   121\t      return 3;\n   122\t    case \"error\":\n   123\t    default:\n   124\t      return 1;\n   125\t  }\n   126\t}\n   127\t\n   128\texport function cliResultEnvelopeSchema<T extends z.ZodTypeAny>(resultSchema: T) {\n   129\t  return z\n   130\t    .object({\n   131\t      command: z.string().min(1),\n   132\t      version: z.literal(1),\n   133\t      status: cliStatusSchema,\n   134\t      outcome: z.string().min(1),\n   135\t      result: resultSchema.optional(),\n   136\t      errors: z.array(cliErrorSchema),\n   137\t      warnings: z.array(z.string()),\n   138\t      artifacts: z.array(cliArtifactRefSchema),\n   139\t      startedAt: z.string().min(1),\n   140\t      finishedAt: z.string().min(1),\n   141\t    })\n   142\t    .superRefine((value, ctx) => {\n   143\t      const expectedStatus = statusForOutcome(value.outcome);\n   144\t      if (expectedStatus !== value.status) {\n   145\t        ctx.addIssue({\n   146\t          code: z.ZodIssueCode.custom,\n   147\t          message: `Envelope status '${value.status}' does not match outcome '${value.outcome}'`,\n   148\t          path: [\"status\"],\n   149\t        });\n   150\t      }\n   151\t    });\n   152\t}\n   153\t\n   154\texport function createResultEnvelope<T>(input: {\n   155\t  command: string;\n   156\t  outcome: string;\n   157\t  result?: T;\n   158\t  errors?: CliError[];\n   159\t  warnings?: string[];\n   160\t  artifacts?: CliArtifactRef[];\n   161\t  startedAt: string;\n   162\t  finishedAt: string;\n   163\t}) {\n   164\t  return {\n   165\t    command: input.command,\n   166\t    version: 1 as const,\n   167\t    status: statusForOutcome(input.outcome),\n   168\t    outcome: input.outcome,\n   169\t    result: input.result,\n   170\t    errors: input.errors ?? [],\n   171\t    warnings: input.warnings ?? [],\n   172\t    artifacts: input.artifacts ?? [],\n   173\t    startedAt: input.startedAt,\n   174\t    finishedAt: input.finishedAt,\n   175\t  };\n   176\t}\n","exit_code":0,"status":"completed"}}
