ailable ? \"ready\" : \"blocked\"}`,\n    46\t    `secondary: ${result.providerMatrix.secondary.length}`,\n    47\t  ];\n    48\t\n    49\t  if (result.verificationGates) {\n    50\t    lines.push(`story gate: ${result.verificationGates.storyGate}`);\n    51\t    lines.push(`epic gate: ${result.verificationGates.epicGate}`);\n    52\t  }\n    53\t\n    54\t  return lines.join(\"\\n\");\n    55\t}\n    56\t\n    57\tfunction emitOutput(params: {\n    58\t  envelope: OutputEnvelope;\n    59\t  json: boolean;\n    60\t}) {\n    61\t  if (params.json) {\n    62\t    console.log(JSON.stringify(params.envelope));\n    63\t    return;\n    64\t  }\n    65\t\n    66\t  console.log(renderHumanSummary(params.envelope));\n    67\t}\n    68\t\n    69\tfunction unavailableProviderErrors(\n    70\t  providerMatrix: PreflightResult[\"providerMatrix\"]\n    71\t): CliError[] {\n    72\t  const errors: CliError[] = [];\n    73\t\n    74\t  if (!providerMatrix.primary.available) {\n    75\t    errors.push({\n    76\t      code: \"PROVIDER_UNAVAILABLE\",\n    77\t      message: \"Primary harness is unavailable\",\n    78\t      detail: providerMatrix.primary.notes.join(\"; \"),\n    79\t    });\n    80\t  }\n    81\t\n    82\t  for (const provider of providerMatrix.secondary) {\n    83\t    if (!provider.available) {\n    84\t      errors.push({\n    85\t        code: \"PROVIDER_UNAVAILABLE\",\n    86\t        message: `Requested secondary harness is unavailable: ${provider.harness}`,\n    87\t        detail: provider.notes.join(\"; \"),\n    88\t      });\n    89\t    }\n    90\t  }\n    91\t\n    92\t  return errors;\n    93\t}\n    94\t\n    95\texport default defineCommand({\n    96\t  meta: {\n    97\t    name: \"preflight\",\n    98\t    description:\n    99\t      \"Validate run config, verification gates, and provider availability.\",\n   100\t  },\n   101\t  args: {\n   102\t    \"spec-pack-root\": {\n   103\t      type: \"string\",\n   104\t      description: \"Absolute or relative path to the spec-pack root\",\n   105\t      required: true,\n   106\t    },\n   107\t    config: {\n   108\t      type: \"string\",\n   109\t      description: \"Explicit run-config file relative to the spec-pack root\",\n   110\t    },\n   111\t    \"story-gate\": {\n   112\t      type: \"string\",\n   113\t      description: \"Explicit story verification gate command\",\n   114\t    },\n   115\t    \"epic-gate\": {\n   116\t      type: \"string\",\n   117\t      description: \"Explicit epic verification gate command\",\n   118\t    },\n   119\t    json: {\n   120\t      type: \"boolean\",\n   121\t      description: \"Emit the structured JSON envelope on stdout\",\n   122\t    },\n   123\t  },\n   124\t  async run({ args }) {\n   125\t    const startedAt = new Date().toISOString();\n   126\t\n   127\t    try {\n   128\t      const inspectResult = await inspectSpecPack(args[\"spec-pack-root\"]);\n   129\t      const artifactPath = await nextArtifactPath(\n   130\t        inspectResult.specPackRoot,\n   131\t        \"preflight\"\n   132\t      );\n   133\t\n   134\t      if (inspectResult.status !== \"ready\") {\n   135\t        const envelope: OutputEnvelope = createResultEnvelope({\n   136\t          command: \"preflight\",\n   137\t          outcome: inspectResult.status,\n   138\t          errors: [\n   139\t            {\n   140\t              code: \"INVALID_SPEC_PACK\",\n   141\t              message:\n   142\t                inspectResult.status === \"blocked\"\n   143\t                  ? \"Spec-pack inspection failed\"\n   144\t                  : \"Spec-pack inspection requires a user decision\",\n   145\t              detail:\n   146\t                inspectResult.blockers.join(\"; \") || inspectResult.notes.join(\"; \"),\n   147\t            },\n   148\t          ],\n   149\t          artifacts: [\n   150\t            {\n   151\t              kind: \"result-envelope\",\n   152\t              path: artifactPath,\n   153\t            },\n   154\t          ],\n   155\t          startedAt,\n   156\t          finishedAt: new Date().toISOString(),\n   157\t        });\n   158\t\n   159\t        await writeJsonArtifact(artifactPath, envelope);\n   160\t        emitOutput({\n   161\t          envelope,\n   162\t          json: Boolean(args.json),\n   163\t        });\n   164\t        process.exitCode = exitCodeForStatus(envelope.status);\n   165\t        return;\n   166\t      }\n   167\t\n   168\t      const validatedConfig = await loadRunConfig({\n   169\t        specPackRoot: inspectResult.specPackRoot,\n   170\t        configPath: args.config,\n   171\t      });\n   172\t      const providerMatrix = await resolveProviderMatrix({\n   173\t        specPackRoot: inspectResult.specPackRoot,\n   174\t        config: validatedConfig,\n   175\t        env: process.env,\n   176\t      });\n   177\t      const gateResolution = await resolveVerificationGates({\n   178\t        specPackRoot: inspectResult.specPackRoot,\n   179\t        explicitStoryGate: args[\"story-gate\"],\n   180\t        explicitEpicGate: args[\"epic-gate\"],\n   181\t      });\n   182\t      const notes = [...inspectResult.notes];\n   183\t\n   184\t      if (\n   185\t        [\n   186\t          validatedConfig.story_implementor,\n   187\t          validatedConfig.quick_fixer,\n   188\t          validatedConfig.story_verifier_1,\n   189\t          validatedConfig.story_verifier_2,\n   190\t          ...validatedConfig.epic_verifiers,\n   191\t          validatedConfig.epic_synthesizer,\n   192\t        ].every((assignment) => assignment.secondary_harness === \"none\")\n   193\t      ) {\n   194\t        notes.push(\n   195\t          \"GPT-capable secondary harnesses are unavailable for this run; the orchestrator should record the Claude-only degraded mode.\"\n   196\t        );\n   197\t      }\n   198\t\n   199\t      const providerErrors = unavailableProviderErrors(providerMatrix);\n   200\t      const blockers: string[] = [];\n   201\t      const errors: CliError[] = [];\n   202\t      let outcome: \"ready\" | \"needs-user-decision\" | \"blocked\" = \"ready\";\n   203\t\n   204\t      if (providerErrors.length > 0) {\n   205\t        outcome = \"blocked\";\n   206\t        errors.push(...providerErrors);\n   207\t        blockers.push(...providerErrors.map((error) => error.message));\n   208\t      } else if (gateResolution.status === \"needs-user-decision\") {\n   209\t        outcome = \"needs-user-decision\";\n   210\t        errors.push(...gateResolution.errors);\n   211\t        notes.push(...gateResolution.notes);\n   212\t      }\n   213\t\n   214\t      const preflightResult: PreflightResult = {\n   215\t        status: outcome,\n   216\t        validatedConfig,\n   217\t        providerMatrix,\n   218\t        verificationGates: gateResolution.verificationGates,\n   219\t        configValidationNotes: [],\n   220\t        promptAssets: {\n   221\t          basePromptsReady: true,\n   222\t          snippetsReady: true,\n   223\t          notes: [],\n   224\t        },\n   225\t        blockers,\n   226\t        notes,\n   227\t      };\n   228\t      const envelope = cliResultEnvelopeSchema(preflightResultSchema).parse(\n   229\t        createResultEnvelope({\n   230\t          command: \"preflight\",\n   231\t          outcome,\n   232\t          result: preflightResult,\n   233\t          errors,\n   234\t          artifacts: [\n   235\t            {\n   236\t              kind: \"result-envelope\",\n   237\t              path: artifactPath,\n   238\t            },\n   239\t          ],\n   240\t          startedAt,\n   241\t          finishedAt: new Date().toISOString(),\n   242\t        })\n   243\t      );\n   244\t\n   245\t      await writeJsonArtifact(artifactPath, envelope);\n   246\t      emitOutput({\n   247\t        envelope,\n   248\t        json: Boolean(args.json),\n   249\t      });\n   250\t      process.exitCode = exitCodeForStatus(envelope.status);\n   251\t    } catch (error) {\n   252\t      if (\n   253\t        error instanceof ZodError ||\n   254\t        (error instanceof Error &&\n   255\t          (error.message.includes(\"Cannot parse\") ||\n   256\t            error.message.includes(\"Required config\") ||\n   257\t            error.message.includes(\"JSON\")))\n   258\t      ) {\n   259\t        const envelope: OutputEnvelope = createResultEnvelope({\n   260\t          command: \"preflight\",\n   261\t          outcome: \"blocked\",\n   262\t          errors: [\n   263\t            {\n   264\t              code: \"INVALID_RUN_CONFIG\",\n   265\t              message: \"Run-config validation failed\",\n   266\t              detail: error instanceof Error ? error.message : String(error),\n   267\t            },\n   268\t          ],\n   269\t          startedAt,\n   270\t          finishedAt: new Date().toISOString(),\n   271\t        });\n   272\t\n   273\t        emitOutput({\n   274\t          envelope,\n   275\t          json: Boolean(args.json),\n   276\t        });\n   277\t        process.exitCode = exitCodeForStatus(envelope.status);\n   278\t        return;\n   279\t      }\n   280\t\n   281\t      const envelope: OutputEnvelope = createResultEnvelope({\n   282\t        command: \"preflight\",\n   283\t        outcome: \"error\",\n   284\t        errors: [\n   285\t          {\n   286\t            code: \"UNEXPECTED_ERROR\",\n   287\t            message: error instanceof Error ? error.message : String(error),\n   288\t          },\n   289\t        ],\n   290\t        startedAt,\n   291\t        finishedAt: new Date().toISOString(),\n   292\t      });\n   293\t\n   294\t      emitOutput({\n   295\t        envelope,\n   296\t        json: Boolean(args.json),\n   297\t      });\n   298\t      process.exitCode = exitCodeForStatus(envelope.status);\n   299\t    }\n   300\t  },\n   301\t});\n","exit_code":0,"status":"completed"}}
docs/spec-build/epics/01-claude-impl-cli-skill/artifacts/story-01/006-verifier-codex53-high.jsonl:32:{"type":"item.completed","item":{"id":"item_15","type":"command_execution","command":"/bin/zsh -lc \"nl -ba /Users/leemoore/code/liminal-spec/src/phases/claude-impl.md | sed -n '1,340p'\"","aggregated_output":"     1\t# Claude Implementation\n     2\t\n     3\tUse `ls-claude-impl` when a completed spec pack already exists and Claude Code needs a disciplined implementation workflow with a bundled bounded-operation CLI.\n     4\t\n     5\t## Startup Orientation\n     6\t\n     7\tResolve the spec-pack root before reading deeply. The minimum v1 layout is:\n     8\t\n     9\t- `epic.md`\n    10\t- `tech-design.md`\n    11\t- `test-plan.md`\n    12\t- `stories/`\n    13\t\n    14\tRun `bin/ls-impl-cli.cjs inspect --spec-pack-root <path> --json` as the first runtime check. Capture the returned tech-design shape, required artifacts, story inventory, and insert status before you move on to run configuration or provider-backed work.\n    15\t\n    16\tRead every story file in `stories/` in order before starting Story 0 or Story 1. Do not begin implementation from a partial story read.\n    17\t\n    18\t## Initialization Steps\n    19\t\n    20\t1. Confirm the spec-pack root and run `inspect`.\n    21\t2. If `team-impl-log.md` is absent, create `team-impl-log.md` and initialize the run in `SETUP`.\n    22\t3. If `team-impl-log.md` already exists, read it first and resume from the recorded state.\n    23\t4. Record whether the spec pack is a two-file or four-file tech-design layout.\n    24\t5. Record whether `custom-story-impl-prompt-insert.md` and `custom-story-verifier-prompt-insert.md` are present. Their absence is non-blocking.\n    25\t6. Discover verification gates in this precedence order: explicit CLI flags, `impl-run.config.json` entries if the run uses them later, package scripts, project policy docs, then CI configuration.\n    26\t7. If the policy stays ambiguous after that precedence order, pause for a user decision instead of improvising.\n    27\t8. Run `preflight` before provider-backed work.\n    28\t9. After `preflight`, record the validated run configuration, available providers, active role defaults, verification gates, and degraded fallback conditions in `team-impl-log.md`.\n    29\t\n    30\t## Default Resolution Contract\n    31\t\n    32\t- Claude Code is the primary harness for every run.\n    33\t- If Codex CLI is available, default the story implementor to Codex `gpt-5.4` with high reasoning.\n    34\t- If Codex CLI is available, default the verifier pair to Codex `gpt-5.4` with extra high reasoning plus Claude Sonnet with high reasoning.\n    35\t- If Codex CLI is available, default epic verifier GPT lanes and the epic synthesizer to Codex `gpt-5.4` with extra high reasoning, paired with a Claude Sonnet verifier lane.\n    36\t- If Codex is unavailable but Copilot CLI is available, use Copilot for the fresh-session GPT roles and keep the retained story implementor on Claude Sonnet high.\n    37\t- If no GPT-capable secondary harness is available, switch the run to Claude-only defaults, record the degraded-diversity condition explicitly, and note that verifier diversity is weaker in this run.\n    38\t\n    39\t## State Ownership\n    40\t\n    41\t- `impl-run.config.json` is orchestrator-owned configuration.\n    42\t- `team-impl-log.md` is the durable run record.\n    43\t- The CLI performs one bounded operation per call and returns structured results.\n    44\t- The CLI does not own story progression, acceptance, or recovery strategy between calls.\n    45\t\n    46\t## Read Next\n    47\t\n    48\tAfter the initial `inspect` pass and log setup, read:\n    49\t\n    50\t1. `references/claude-impl-reading-journey.md`\n    51\t2. `references/claude-impl-process-playbook.md`\n    52\t3. `references/claude-impl-cli-operations.md`\n    53\t4. `references/claude-impl-prompt-system.md`\n","exit_code":0,"status":"completed"}}
