tchAll(/^Epic Gate:\\s*(.+)$/gim)) {\n   112\t      candidates.epic.push(match[1]);\n   113\t    }\n   114\t  }\n   115\t\n   116\t  if (candidates.story.length === 0 && candidates.epic.length === 0) {\n   117\t    return [];\n   118\t  }\n   119\t\n   120\t  return [candidates];\n   121\t}\n   122\t\n   123\tasync function ciCandidates(specPackRoot: string): Promise<GateSourceCandidates[]> {\n   124\t  const workflowsDir = join(specPackRoot, \".github\", \"workflows\");\n   125\t  if (!(await pathExists(workflowsDir))) {\n   126\t    return [];\n   127\t  }\n   128\t\n   129\t  const entries = await readdir(workflowsDir, { withFileTypes: true });\n   130\t  const candidates: GateSourceCandidates = {\n   131\t    story: [],\n   132\t    epic: [],\n   133\t    source: \"CI configuration\",\n   134\t  };\n   135\t\n   136\t  for (const entry of entries) {\n   137\t    if (!entry.isFile() || !entry.name.match(/\\.ya?ml$/)) {\n   138\t      continue;\n   139\t    }\n   140\t\n   141\t    const content = await readTextFile(join(workflowsDir, entry.name));\n   142\t    for (const match of content.matchAll(/run:\\s*(.+)$/gim)) {\n   143\t      const command = match[1].trim();\n   144\t      if (command.includes(\"green-verify\")) {\n   145\t        candidates.story.push(command);\n   146\t      }\n   147\t      if (command.includes(\"verify-all\")) {\n   148\t        candidates.epic.push(command);\n   149\t      }\n   150\t    }\n   151\t  }\n   152\t\n   153\t  if (candidates.story.length === 0 && candidates.epic.length === 0) {\n   154\t    return [];\n   155\t  }\n   156\t\n   157\t  return [candidates];\n   158\t}\n   159\t\n   160\texport async function resolveVerificationGates(input: {\n   161\t  specPackRoot: string;\n   162\t  explicitStoryGate?: string;\n   163\t  explicitEpicGate?: string;\n   164\t}): Promise<GateDiscoveryResult> {\n   165\t  const specPackRoot = resolve(input.specPackRoot);\n   166\t  const sourceCandidates = [\n   167\t    ...(await packageScriptCandidates(specPackRoot)),\n   168\t    ...(await docCandidates(specPackRoot)),\n   169\t    ...(await ciCandidates(specPackRoot)),\n   170\t  ];\n   171\t  const storyResolution = resolveGateValue({\n   172\t    explicitValue: input.explicitStoryGate,\n   173\t    sourceCandidates,\n   174\t    gate: \"story\",\n   175\t  });\n   176\t  const epicResolution = resolveGateValue({\n   177\t    explicitValue: input.explicitEpicGate,\n   178\t    sourceCandidates,\n   179\t    gate: \"epic\",\n   180\t  });\n   181\t\n   182\t  if (\n   183\t    storyResolution.ambiguous ||\n   184\t    epicResolution.ambiguous ||\n   185\t    !storyResolution.value ||\n   186\t    !epicResolution.value ||\n   187\t    !storyResolution.source ||\n   188\t    !epicResolution.source\n   189\t  ) {\n   190\t    return {\n   191\t      status: \"needs-user-decision\",\n   192\t      errors: [\n   193\t        {\n   194\t          code: \"VERIFICATION_GATE_UNRESOLVED\",\n   195\t          message: \"Verification gate policy is ambiguous\",\n   196\t          detail:\n   197\t            \"Provide --story-gate and --epic-gate explicitly or clarify the project policy.\",\n   198\t        },\n   199\t      ],\n   200\t      notes: [],\n   201\t    };\n   202\t  }\n   203\t\n   204\t  return {\n   205\t    status: \"ready\",\n   206\t    verificationGates: {\n   207\t      storyGate: storyResolution.value,\n   208\t      epicGate: epicResolution.value,\n   209\t      storyGateSource: storyResolution.source,\n   210\t      epicGateSource: epicResolution.source,\n   211\t    },\n   212\t    errors: [],\n   213\t    notes: [],\n   214\t  };\n   215\t}\n","exit_code":0,"status":"completed"}}
