t\",\n   105\t      required: true,\n   106\t    },\n   107\t    config: {\n   108\t      type: \"string\",\n   109\t      description: \"Explicit run-config file relative to the spec-pack root\",\n   110\t    },\n   111\t    \"story-gate\": {\n   112\t      type: \"string\",\n   113\t      description: \"Explicit story verification gate command\",\n   114\t    },\n   115\t    \"epic-gate\": {\n   116\t      type: \"string\",\n   117\t      description: \"Explicit epic verification gate command\",\n   118\t    },\n   119\t    json: {\n   120\t      type: \"boolean\",\n   121\t      description: \"Emit the structured JSON envelope on stdout\",\n   122\t    },\n   123\t  },\n   124\t  async run({ args }) {\n   125\t    const startedAt = new Date().toISOString();\n   126\t\n   127\t    try {\n   128\t      const inspectResult = await inspectSpecPack(args[\"spec-pack-root\"]);\n   129\t      const artifactPath = await nextArtifactPath(\n   130\t        inspectResult.specPackRoot,\n   131\t        \"preflight\"\n   132\t      );\n   133\t\n   134\t      if (inspectResult.status !== \"ready\") {\n   135\t        const envelope: OutputEnvelope = createResultEnvelope({\n   136\t          command: \"preflight\",\n   137\t          outcome: inspectResult.status,\n   138\t          errors: [\n   139\t            {\n   140\t              code: \"INVALID_SPEC_PACK\",\n   141\t              message:\n   142\t                inspectResult.status === \"blocked\"\n   143\t                  ? \"Spec-pack inspection failed\"\n   144\t                  : \"Spec-pack inspection requires a user decision\",\n   145\t              detail:\n   146\t                inspectResult.blockers.join(\"; \") || inspectResult.notes.join(\"; \"),\n   147\t            },\n   148\t          ],\n   149\t          artifacts: [\n   150\t            {\n   151\t              kind: \"result-envelope\",\n   152\t              path: artifactPath,\n   153\t            },\n   154\t          ],\n   155\t          